      vi.advanceTimersByTime(1000);
      await tick();
      expect(screen.getByTestId("nlq-elapsed-time")).toHaveTextContent("1s");

      vi.advanceTimersByTime(1000);
      await tick();
      expect(screen.getByTestId("nlq-elapsed-time")).toHaveTextContent("2s");

      vi.advanceTimersByTime(1000);
